import * as Tone from 'tone'

export class SoccerJugglingAudioManager {
	private initialized = false
	private muted = false

	private kickSynth: Tone.MembraneSynth | null = null
	private perfectSynth: Tone.PolySynth | null = null
	private comboSynth: Tone.Synth | null = null
	private missSynth: Tone.Synth | null = null
	private gameOverSynth: Tone.PolySynth | null = null

	async init(): Promise<void> {
		if (this.initialized) return

		await Tone.start()

		// Kick synth - short punchy hit
		this.kickSynth = new Tone.MembraneSynth({
			pitchDecay: 0.015,
			octaves: 4,
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.001,
				decay: 0.15,
				sustain: 0,
				release: 0.1,
			},
			volume: -6,
		}).toDestination()

		// Perfect kick synth - bright chord
		this.perfectSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'triangle' },
			envelope: {
				attack: 0.01,
				decay: 0.15,
				sustain: 0.1,
				release: 0.3,
			},
			volume: -10,
		}).toDestination()

		// Combo milestone synth - ascending tone
		this.comboSynth = new Tone.Synth({
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.01,
				decay: 0.2,
				sustain: 0.1,
				release: 0.2,
			},
			volume: -8,
		}).toDestination()

		// Miss / life lost synth - descending wobble
		this.missSynth = new Tone.Synth({
			oscillator: { type: 'triangle' },
			envelope: {
				attack: 0.01,
				decay: 0.3,
				sustain: 0,
				release: 0.3,
			},
			volume: -8,
		}).toDestination()

		// Game over synth - sad descending
		this.gameOverSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'sawtooth' },
			envelope: {
				attack: 0.01,
				decay: 0.3,
				sustain: 0.2,
				release: 0.5,
			},
			volume: -10,
		}).toDestination()

		this.initialized = true
	}

	playKick(): void {
		if (!this.initialized || this.muted || !this.kickSynth) return
		this.kickSynth.triggerAttackRelease('C3', '16n', Tone.now())
	}

	playPerfectKick(): void {
		if (!this.initialized || this.muted || !this.perfectSynth) return
		const now = Tone.now()
		this.perfectSynth.triggerAttackRelease(['E5', 'G5', 'B5'], '8n', now)
	}

	playComboMilestone(comboLevel: number): void {
		if (!this.initialized || this.muted || !this.comboSynth) return
		const now = Tone.now()
		// Higher pitch for higher combos
		const notes = ['C5', 'D5', 'E5', 'F5', 'G5', 'A5', 'B5', 'C6']
		const note = notes[Math.min(comboLevel, notes.length - 1)]
		this.comboSynth.triggerAttackRelease(note, '8n', now)
	}

	playMiss(): void {
		if (!this.initialized || this.muted || !this.missSynth) return
		const now = Tone.now()
		const notes = ['E4', 'D4', 'C4']
		notes.forEach((note, i) => {
			this.missSynth!.triggerAttackRelease(note, '16n', now + i * 0.1)
		})
	}

	playCountdownTick(): void {
		if (!this.initialized || this.muted || !this.comboSynth) return
		this.comboSynth.triggerAttackRelease('G4', '16n', Tone.now())
	}

	playCountdownGo(): void {
		if (!this.initialized || this.muted || !this.perfectSynth) return
		this.perfectSynth.triggerAttackRelease(['C5', 'E5', 'G5'], '8n', Tone.now())
	}

	playGameOver(): void {
		if (!this.initialized || this.muted || !this.gameOverSynth) return
		const now = Tone.now()
		const chords = [
			{ notes: ['E4', 'G4', 'B4'], time: 0 },
			{ notes: ['D4', 'F4', 'A4'], time: 0.25 },
			{ notes: ['C4', 'E4', 'G4'], time: 0.5 },
			{ notes: ['B3', 'D4', 'F4'], time: 0.75 },
		]
		chords.forEach(({ notes, time }) => {
			this.gameOverSynth!.triggerAttackRelease(notes, '4n', now + time)
		})
	}

	setMuted(muted: boolean): void {
		this.muted = muted
	}

	dispose(): void {
		if (!this.initialized) return
		this.kickSynth?.dispose()
		this.perfectSynth?.dispose()
		this.comboSynth?.dispose()
		this.missSynth?.dispose()
		this.gameOverSynth?.dispose()
		this.kickSynth = null
		this.perfectSynth = null
		this.comboSynth = null
		this.missSynth = null
		this.gameOverSynth = null
		this.initialized = false
	}
}

export const soccerJugglingAudio = new SoccerJugglingAudioManager()
