import React, { useEffect, useRef, useCallback } from 'react'
import Phaser from 'phaser'
import { BootScene } from './scenes/BootScene'
import { MainScene } from './scenes/MainScene'
import { GAME_WIDTH, GAME_HEIGHT } from './constants'
import { hapticManager } from '../utils/hapticManager'

interface SoccerJugglingCoreProps {
	onScoreUpdate: (score: number) => void
	onLifeLost: (livesRemaining: number) => void
	onGameOver: (totalScore: number, kicks: number) => void
	onKick: (kicks: number) => void
	brandColor?: string
	lives?: number
	skin?: string
	isPaused?: boolean
	onPauseChange?: (paused: boolean) => void
}

const SoccerJugglingCore: React.FC<SoccerJugglingCoreProps> = ({
	onScoreUpdate,
	onLifeLost,
	onGameOver,
	onKick,
	brandColor,
	lives = 3,
	skin,
	isPaused = false,
	onPauseChange,
}) => {
	const gameContainerRef = useRef<HTMLDivElement>(null)
	const gameRef = useRef<Phaser.Game | null>(null)

	const handleScoreUpdate = useCallback(
		(score: number) => {
			onScoreUpdate(score)
			hapticManager.goodHit()
		},
		[onScoreUpdate]
	)

	const handleLifeLost = useCallback(
		(livesRemaining: number) => {
			onLifeLost(livesRemaining)
			hapticManager.miss()
		},
		[onLifeLost]
	)

	const handleGameOver = useCallback(
		(totalScore: number, kicks: number) => {
			onGameOver(totalScore, kicks)
		},
		[onGameOver]
	)

	const handleKick = useCallback(
		(kicks: number) => {
			onKick(kicks)
		},
		[onKick]
	)

	useEffect(() => {
		if (!gameContainerRef.current || gameRef.current) return

		hapticManager.init()

		const config: Phaser.Types.Core.GameConfig = {
			type: Phaser.AUTO,
			parent: gameContainerRef.current,
			width: GAME_WIDTH,
			height: GAME_HEIGHT,
			backgroundColor: '#87ceeb',
			physics: {
				default: 'arcade',
				arcade: {
					gravity: { x: 0, y: 0 },
					debug: false,
				},
			},
			scene: [BootScene, MainScene],
			scale: {
				mode: Phaser.Scale.FIT,
				autoCenter: Phaser.Scale.CENTER_BOTH,
			},
			render: {
				pixelArt: false,
				antialias: true,
			},
			input: {
				activePointers: 1,
			},
		}

		gameRef.current = new Phaser.Game(config)

		// Pass callbacks to Phaser via registry
		gameRef.current.registry.set('onScoreUpdate', handleScoreUpdate)
		gameRef.current.registry.set('onLifeLost', handleLifeLost)
		gameRef.current.registry.set('onGameOver', handleGameOver)
		gameRef.current.registry.set('onKick', handleKick)
		gameRef.current.registry.set('brandColor', brandColor)
		gameRef.current.registry.set('lives', lives)
		gameRef.current.registry.set('skin', skin)

		return () => {
			if (gameRef.current) {
				gameRef.current.destroy(true)
				gameRef.current = null
			}
		}
	}, [
		handleScoreUpdate,
		handleLifeLost,
		handleGameOver,
		handleKick,
		brandColor,
		lives,
		skin,
	])

	// Sync pause state from React to Phaser
	useEffect(() => {
		if (gameRef.current) {
			gameRef.current.registry.set('externalPause', isPaused)
		}
	}, [isPaused])

	// Register onPauseChange callback so Phaser can notify React
	useEffect(() => {
		if (gameRef.current) {
			gameRef.current.registry.set('onPauseChange', onPauseChange)
		}
	}, [onPauseChange])

	return (
		<div
			ref={gameContainerRef}
			className="game-loading"
			style={{
				touchAction: 'none',
				userSelect: 'none',
			}}
		/>
	)
}

export default SoccerJugglingCore
