import Phaser from 'phaser'
import {
	GAME_WIDTH,
	GAME_HEIGHT,
	PHYSICS,
	LAYOUT,
	BALL,
	SCORING,
	WIND,
	SPIN,
	COLORS,
	GAME_FONT,
	PORTAL,
	COUNTDOWN,
} from '../constants'
import { soccerJugglingAudio } from '../utils/audioManager'

export class MainScene extends Phaser.Scene {
	// Ball
	private ball!: Phaser.Physics.Arcade.Sprite
	private ballShadow!: Phaser.GameObjects.Ellipse

	// State
	private score: number = 0
	private kicks: number = 0
	private lives: number = 3
	private maxLives: number = 3
	private combo: number = 0
	private lastKickTime: number = 0
	private isGameOver: boolean = false
	private isResetting: boolean = false
	private isPaused: boolean = false
	private isCountingDown: boolean = false
	private currentGravity: number = PHYSICS.initialGravity
	private spinRate: number = 0 // Angular velocity deg/sec, positive = clockwise

	// Portal mechanic
	private cornerKickHistory: number[] = []
	private isPortalActive: boolean = false
	private portalGraphics: Phaser.GameObjects.Graphics | null = null

	// Wind
	private windForce: number = 0
	private windDirection: number = 0
	private lastWindChange: number = 0
	private windText!: Phaser.GameObjects.Text

	// HUD (in-canvas)
	private hudScore!: Phaser.GameObjects.Text
	private hudCombo!: Phaser.GameObjects.Text
	private hudLives!: Phaser.GameObjects.Text
	private hudKicks!: Phaser.GameObjects.Text
	private pauseOverlay!: Phaser.GameObjects.Rectangle
	private pauseText!: Phaser.GameObjects.Text

	// Particles
	private kickEmitter!: Phaser.GameObjects.Particles.ParticleEmitter

	constructor() {
		super({ key: 'MainScene' })
	}

	create() {
		// Read config from registry
		this.maxLives = this.registry.get('lives') || 3
		this.lives = this.maxLives

		// Initialize audio
		soccerJugglingAudio.init()

		this.score = 0
		this.kicks = 0
		this.combo = 0
		this.lastKickTime = 0
		this.isGameOver = false
		this.isResetting = true
		this.isPaused = false
		this.isCountingDown = false
		this.currentGravity = PHYSICS.initialGravity
		this.windForce = 0
		this.windDirection = 0
		this.lastWindChange = 0
		this.cornerKickHistory = []
		this.isPortalActive = false
		this.spinRate = 0

		this.drawBackground()
		this.createBall()
		this.createParticles()
		this.createHUD()
		this.createWindIndicator()
		this.createPauseOverlay()
		this.setupInput()

		// Listen for external pause changes from React
		this.registry.events.on(
			'changedata-externalPause',
			(_parent: unknown, value: boolean) => {
				if (value && !this.isPaused) {
					this.setPaused(true)
				} else if (!value && this.isPaused) {
					this.setPaused(false)
				}
			}
		)

		// Start with gravity disabled, countdown will enable it
		const body = this.ball.body as Phaser.Physics.Arcade.Body
		if (body) {
			body.setGravityY(0)
		}

		this.startCountdown(() => {
			const b = this.ball.body as Phaser.Physics.Arcade.Body
			if (b) {
				b.setGravityY(this.currentGravity)
			}
			this.isResetting = false
		})
	}

	private drawBackground() {
		const bg = this.add.image(GAME_WIDTH / 2, GAME_HEIGHT / 2, 'background')
		bg.setDisplaySize(GAME_WIDTH, GAME_HEIGHT)
		bg.setDepth(0)
	}

	private createBall() {
		// Shadow
		this.ballShadow = this.add.ellipse(
			BALL.startX,
			LAYOUT.floorY - 4,
			BALL.shadowWidth,
			BALL.shadowHeight,
			0x000000,
			0.45
		)
		this.ballShadow.setDepth(1)

		// Ball with arcade physics — uses loaded sprite from penalty-shootout
		this.ball = this.physics.add.sprite(BALL.startX, BALL.startY, 'soccer-ball')
		this.ball.setDepth(5)
		this.ball.setCircle(BALL.textureSize / 2)
		this.ball.setDisplaySize(PHYSICS.ballRadius * 2, PHYSICS.ballRadius * 2)
		this.ball.setBounce(0)
		this.ball.setCollideWorldBounds(false)

		// Set initial gravity
		if (this.ball.body) {
			const body = this.ball.body as Phaser.Physics.Arcade.Body
			body.setGravityY(this.currentGravity)
			body.setMaxVelocity(300, PHYSICS.maxVelocityY)
		}
	}

	private createParticles() {
		this.kickEmitter = this.add.particles(0, 0, 'kick-particle', {
			speed: { min: 50, max: 150 },
			scale: { start: 1.2, end: 0 },
			alpha: { start: 0.8, end: 0 },
			lifespan: 400,
			quantity: 8,
			emitting: false,
		})
		this.kickEmitter.setDepth(4)
	}

	private createHUD() {
		// Score — large, top center
		this.hudScore = this.add.text(GAME_WIDTH / 2, 16, '0', {
			fontFamily: GAME_FONT,
			fontSize: '42px',
			color: COLORS.hudText,
			stroke: '#000000',
			strokeThickness: 6,
		})
		this.hudScore.setOrigin(0.5, 0)
		this.hudScore.setDepth(20)
		this.hudScore.setResolution(2)

		// Combo — below score, flashy
		this.hudCombo = this.add.text(GAME_WIDTH / 2, 62, '', {
			fontFamily: GAME_FONT,
			fontSize: '24px',
			color: COLORS.comboText,
			stroke: '#000000',
			strokeThickness: 4,
		})
		this.hudCombo.setOrigin(0.5, 0)
		this.hudCombo.setDepth(20)
		this.hudCombo.setResolution(2)

		// Lives — top left, hearts
		this.hudLives = this.add.text(14, 18, this.getLivesText(), {
			fontSize: '26px',
			color: '#ffffff',
			stroke: '#000000',
			strokeThickness: 3,
		})
		this.hudLives.setDepth(20)

		// Kicks counter — top right
		this.hudKicks = this.add.text(GAME_WIDTH - 14, 22, '0', {
			fontFamily: GAME_FONT,
			fontSize: '20px',
			color: '#ffffff',
			stroke: '#000000',
			strokeThickness: 4,
		})
		this.hudKicks.setOrigin(1, 0)
		this.hudKicks.setDepth(20)
		this.hudKicks.setResolution(2)

		// Kicks label above counter
		const kicksLabel = this.add.text(GAME_WIDTH - 14, 8, 'TOQUES', {
			fontFamily: GAME_FONT,
			fontSize: '10px',
			color: '#aaaaaa',
			stroke: '#000000',
			strokeThickness: 2,
		})
		kicksLabel.setOrigin(1, 0)
		kicksLabel.setDepth(20)
		kicksLabel.setResolution(2)
	}

	private createWindIndicator() {
		this.windText = this.add.text(GAME_WIDTH / 2, 90, '', {
			fontFamily: GAME_FONT,
			fontSize: '14px',
			color: '#88bbff',
			stroke: '#000000',
			strokeThickness: 3,
		})
		this.windText.setOrigin(0.5, 0)
		this.windText.setDepth(20)
		this.windText.setVisible(false)
		this.windText.setResolution(2)
	}

	private createPauseOverlay() {
		// Dark overlay
		this.pauseOverlay = this.add.rectangle(
			GAME_WIDTH / 2,
			GAME_HEIGHT / 2,
			GAME_WIDTH,
			GAME_HEIGHT,
			0x000000,
			0.6
		)
		this.pauseOverlay.setDepth(50)
		this.pauseOverlay.setVisible(false)

		// Pause text
		this.pauseText = this.add.text(GAME_WIDTH / 2, GAME_HEIGHT / 2, 'PAUSA', {
			fontFamily: GAME_FONT,
			fontSize: '48px',
			color: '#ffffff',
			stroke: '#000000',
			strokeThickness: 6,
			align: 'center',
		})
		this.pauseText.setOrigin(0.5)
		this.pauseText.setDepth(51)
		this.pauseText.setVisible(false)
		this.pauseText.setResolution(2)
	}

	private setPaused(paused: boolean) {
		if (this.isGameOver || this.isResetting || this.isCountingDown) return
		if (paused === this.isPaused) return

		this.isPaused = paused

		if (this.isPaused) {
			this.physics.pause()
			this.pauseOverlay.setVisible(true)
			this.pauseText.setVisible(true)
		} else {
			this.physics.resume()
			this.pauseOverlay.setVisible(false)
			this.pauseText.setVisible(false)
		}
	}

	private setupInput() {
		// Touch / click — only kick (pause/resume handled by React overlay)
		this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
			if (this.isGameOver || this.isPaused) return
			this.handleKick(pointer.x, pointer.y)
		})

		// Spacebar = pause/resume — notify React so state stays in sync
		if (this.input.keyboard) {
			this.input.keyboard.on('keydown-SPACE', () => {
				if (this.isGameOver) return
				const onPauseChange = this.registry.get('onPauseChange')
				if (onPauseChange) {
					onPauseChange(!this.isPaused)
				}
			})
		}
	}

	private startCountdown(onComplete: () => void) {
		this.isCountingDown = true
		let stepIndex = 0

		const showStep = () => {
			if (stepIndex >= COUNTDOWN.steps.length) {
				this.isCountingDown = false
				onComplete()
				return
			}

			const step = COUNTDOWN.steps[stepIndex]
			const isGo = stepIndex === COUNTDOWN.steps.length - 1

			// Play sound
			if (isGo) {
				soccerJugglingAudio.playCountdownGo()
			} else {
				soccerJugglingAudio.playCountdownTick()
			}

			const countdownText = this.add.text(
				GAME_WIDTH / 2,
				GAME_HEIGHT / 2 - 40,
				step,
				{
					fontFamily: GAME_FONT,
					fontSize: isGo ? COUNTDOWN.goFontSize : COUNTDOWN.numberFontSize,
					color: isGo ? COUNTDOWN.goColor : COUNTDOWN.numberColor,
					stroke: '#000000',
					strokeThickness: 8,
					align: 'center',
					padding: { bottom: 8 },
				}
			)
			countdownText.setOrigin(0.5)
			countdownText.setDepth(30)
			countdownText.setResolution(2)
			countdownText.setScale(0.3)
			countdownText.setAlpha(1)

			this.tweens.add({
				targets: countdownText,
				scale: { from: 0.3, to: 1.5 },
				alpha: { from: 1, to: 0 },
				duration: COUNTDOWN.stepDurationMs,
				ease: 'Power2',
				onComplete: () => {
					countdownText.destroy()
					stepIndex++
					showStep()
				},
			})
		}

		showStep()
	}

	private handleKick(tapX: number, tapY: number) {
		if (
			this.isResetting ||
			this.isPaused ||
			this.isCountingDown ||
			this.isPortalActive
		)
			return

		const dist = Phaser.Math.Distance.Between(
			tapX,
			tapY,
			this.ball.x,
			this.ball.y
		)

		// Must tap near the ball
		if (dist > SCORING.maxHitDistance) return

		const body = this.ball.body as Phaser.Physics.Arcade.Body
		if (!body) return

		// Determine kick quality
		const isPerfect = dist <= SCORING.perfectHitDistance

		// Calculate risky bonus (ball near floor)
		const distFromFloor = LAYOUT.floorY - this.ball.y
		let riskyBonus = 0
		if (distFromFloor < LAYOUT.dangerZoneHeight) {
			const tiers = Math.ceil(
				(LAYOUT.dangerZoneHeight - distFromFloor) / SCORING.riskyTierHeight
			)
			riskyBonus = tiers * SCORING.riskyKickBonusPerTier
		}

		// Update combo
		const now = this.time.now
		if (now - this.lastKickTime > SCORING.comboTimeoutMs) {
			this.combo = 0
		}
		this.combo++
		this.lastKickTime = now

		const comboIndex = Math.min(
			this.combo - 1,
			SCORING.comboMultipliers.length - 1
		)
		const multiplier = SCORING.comboMultipliers[comboIndex]

		// Calculate points
		let basePoints = SCORING.normalKick
		if (isPerfect) {
			basePoints += SCORING.perfectKickBonus
		}
		basePoints += riskyBonus

		const points = Math.floor(basePoints * multiplier)
		this.score += points
		this.kicks++

		// Apply kick force
		const kickForceY =
			PHYSICS.kickUpForce - Math.random() * PHYSICS.kickUpForceVariance

		// Horizontal force: kick slightly away from tap direction
		const offsetX = this.ball.x - tapX
		const spinVelocityBonus = this.spinRate * SPIN.spinToVelocityOnKick
		const horizontalForce =
			offsetX * 1.5 +
			(Math.random() - 0.5) * PHYSICS.kickHorizontalForce +
			spinVelocityBonus

		body.setVelocity(
			Phaser.Math.Clamp(body.velocity.x + horizontalForce, -300, 300),
			kickForceY
		)

		// Impart new spin based on tap offset
		const retainedSpin = this.spinRate * SPIN.kickSpinRetention
		const impartedSpin =
			offsetX * SPIN.kickSpinFactor +
			(Math.random() - 0.5) * 2 * SPIN.randomSpinJitter
		this.spinRate = Phaser.Math.Clamp(
			retainedSpin + impartedSpin,
			-SPIN.maxSpinRate,
			SPIN.maxSpinRate
		)

		// Track kick position for corner exploit detection
		this.cornerKickHistory.push(this.ball.x)
		if (this.cornerKickHistory.length > PORTAL.kickHistorySize) {
			this.cornerKickHistory.shift()
		}
		this.checkCornerExploit()

		// Visuals
		this.spawnKickParticles(isPerfect)
		this.showFloatingScore(points, isPerfect, multiplier)

		// Audio + haptics
		if (isPerfect) {
			soccerJugglingAudio.playPerfectKick()
		} else {
			soccerJugglingAudio.playKick()
		}

		// Combo milestone audio
		if (this.combo > 1 && this.combo % 5 === 0) {
			soccerJugglingAudio.playComboMilestone(Math.floor(this.combo / 5))
		}

		// Difficulty progression
		if (this.kicks % PHYSICS.kicksPerGravityIncrease === 0) {
			this.currentGravity = Math.min(
				PHYSICS.maxGravity,
				this.currentGravity + PHYSICS.gravityIncrement
			)
			body.setGravityY(this.currentGravity)
		}

		// Update HUD
		this.updateHUD()

		// Notify React
		const onScoreUpdate = this.registry.get('onScoreUpdate')
		if (onScoreUpdate) onScoreUpdate(this.score)

		const onKick = this.registry.get('onKick')
		if (onKick) onKick(this.kicks)
	}

	private spawnKickParticles(isPerfect: boolean) {
		const tint = isPerfect
			? [COLORS.particleRed, COLORS.particleGold]
			: [COLORS.particleGold, COLORS.particleWhite]

		this.kickEmitter.setParticleTint(tint)
		this.kickEmitter.emitParticleAt(
			this.ball.x,
			this.ball.y,
			isPerfect ? 12 : 8
		)
	}

	private showFloatingScore(
		points: number,
		isPerfect: boolean,
		multiplier: number
	) {
		let text = `+${points}`
		if (multiplier > 1) {
			text += `  x${multiplier}`
		}
		if (isPerfect) {
			text += '\nPERFECTO!'
		}

		const floatText = this.add.text(this.ball.x, this.ball.y - 30, text, {
			fontFamily: GAME_FONT,
			fontSize: isPerfect ? '22px' : '18px',
			color: isPerfect ? '#ff4444' : '#ffd700',
			stroke: '#000000',
			strokeThickness: 4,
			align: 'center',
		})
		floatText.setOrigin(0.5)
		floatText.setDepth(15)
		floatText.setResolution(2)

		this.tweens.add({
			targets: floatText,
			y: floatText.y - 70,
			alpha: { from: 1, to: 0 },
			scale: { from: 1, to: 1.4 },
			duration: 900,
			ease: 'Power2',
			onComplete: () => floatText.destroy(),
		})
	}

	private getLivesText(): string {
		let text = ''
		for (let i = 0; i < this.maxLives; i++) {
			text += i < this.lives ? '❤️' : '🖤'
		}
		return text
	}

	private updateHUD() {
		this.hudScore.setText(this.score.toString())
		this.hudKicks.setText(this.kicks.toString())
		this.hudLives.setText(this.getLivesText())

		// Combo display
		if (this.combo > 1) {
			const comboIndex = Math.min(
				this.combo - 1,
				SCORING.comboMultipliers.length - 1
			)
			const multiplier = SCORING.comboMultipliers[comboIndex]
			this.hudCombo.setText(`COMBO x${multiplier}`)
			this.hudCombo.setVisible(true)

			// Pulse combo text on increase
			this.tweens.killTweensOf(this.hudCombo)
			this.hudCombo.setScale(1)
			this.tweens.add({
				targets: this.hudCombo,
				scale: { from: 1.3, to: 1 },
				duration: 200,
				ease: 'Back.easeOut',
			})
		} else {
			this.hudCombo.setVisible(false)
		}
	}

	private updateWindIndicator() {
		if (this.kicks < WIND.activateAfterKicks) {
			this.windText.setVisible(false)
			return
		}

		this.windText.setVisible(true)
		this.windText.setText(this.windDirection > 0 ? 'Viento >' : '< Viento')
	}

	// --- Portal mechanic ---

	private checkCornerExploit() {
		if (this.cornerKickHistory.length < PORTAL.consecutiveCornerKicksToTrigger)
			return

		const recentKicks = this.cornerKickHistory.slice(
			-PORTAL.consecutiveCornerKicksToTrigger
		)

		const allNearLeft = recentKicks.every(x => x < PORTAL.wallProximity)
		const allNearRight = recentKicks.every(
			x => x > GAME_WIDTH - PORTAL.wallProximity
		)

		if (allNearLeft || allNearRight) {
			this.cornerKickHistory = []
			this.activatePortal()
		}
	}

	private activatePortal() {
		this.isPortalActive = true

		const body = this.ball.body as Phaser.Physics.Arcade.Body
		if (!body) return

		// Freeze ball physics
		body.setVelocity(0, 0)
		body.setGravityY(0)
		body.setAccelerationX(0)

		const entryX = this.ball.x
		const entryY = this.ball.y

		// Calculate exit position (upper half, away from walls)
		const exitX = Phaser.Math.Between(
			PORTAL.exitMarginX,
			GAME_WIDTH - PORTAL.exitMarginX
		)
		const exitY = Phaser.Math.Between(PORTAL.exitMinY, PORTAL.exitMaxY)

		const halfDuration = PORTAL.animationDurationMs / 2

		// Create entry portal graphics
		this.portalGraphics = this.add.graphics()
		this.portalGraphics.setDepth(10)

		// Phase 1: Entry portal opens, ball shrinks into it
		this.drawPortalCircle(this.portalGraphics, entryX, entryY, 0)

		// Animate entry portal expanding
		const portalScale = { value: 0 }
		this.tweens.add({
			targets: portalScale,
			value: 1,
			duration: halfDuration * 0.5,
			ease: 'Back.easeOut',
			onUpdate: () => {
				if (this.portalGraphics) {
					this.portalGraphics.clear()
					this.drawPortalCircle(
						this.portalGraphics,
						entryX,
						entryY,
						PORTAL.portalRadius * portalScale.value
					)
				}
			},
		})

		// Ball shrinks and spins into portal
		this.tweens.add({
			targets: this.ball,
			scaleX: 0,
			scaleY: 0,
			angle: this.ball.angle + 720,
			duration: halfDuration,
			ease: 'Power2',
			onComplete: () => {
				// Teleport ball to exit position
				this.ball.setPosition(exitX, exitY)
				this.ballShadow.setVisible(false)

				// Fade out entry portal, draw exit portal
				if (this.portalGraphics) {
					this.portalGraphics.clear()
				}

				// Phase 2: Exit portal opens, ball grows out
				const exitPortalScale = { value: 0 }
				this.tweens.add({
					targets: exitPortalScale,
					value: 1,
					duration: halfDuration * 0.5,
					ease: 'Back.easeOut',
					onUpdate: () => {
						if (this.portalGraphics) {
							this.portalGraphics.clear()
							this.drawPortalCircle(
								this.portalGraphics,
								exitX,
								exitY,
								PORTAL.portalRadius * exitPortalScale.value
							)
						}
					},
				})

				// Ball grows and spins out
				this.tweens.add({
					targets: this.ball,
					scaleX: 1,
					scaleY: 1,
					angle: this.ball.angle + 720,
					duration: halfDuration,
					ease: 'Back.easeOut',
					onComplete: () => {
						// Clean up portal
						if (this.portalGraphics) {
							this.portalGraphics.destroy()
							this.portalGraphics = null
						}

						// Re-enable physics
						body.setGravityY(this.currentGravity)
						body.setVelocityY(PORTAL.exitVelocityY)
						body.setVelocityX((Math.random() - 0.5) * PORTAL.exitVelocityXRange)
						this.spinRate = 0

						this.ballShadow.setVisible(true)
						this.isPortalActive = false
					},
				})
			},
		})
	}

	private drawPortalCircle(
		graphics: Phaser.GameObjects.Graphics,
		x: number,
		y: number,
		radius: number
	) {
		if (radius <= 0) return

		// Outer glow
		graphics.fillStyle(PORTAL.portalGlowColor, 0.2)
		graphics.fillCircle(x, y, radius * 1.3)

		// Main ring
		graphics.lineStyle(4, PORTAL.portalColor, 0.8)
		graphics.strokeCircle(x, y, radius)

		// Inner ring
		graphics.lineStyle(2, PORTAL.portalGlowColor, 0.6)
		graphics.strokeCircle(x, y, radius * 0.6)

		// Bright center
		graphics.fillStyle(0xffffff, 0.4)
		graphics.fillCircle(x, y, radius * 0.3)
	}

	private handleLifeLost() {
		if (this.isResetting || this.isGameOver) return
		this.isResetting = true

		this.lives--
		this.combo = 0

		soccerJugglingAudio.playMiss()

		// Notify React
		const onLifeLost = this.registry.get('onLifeLost')
		if (onLifeLost) onLifeLost(this.lives)

		this.updateHUD()

		// Flash screen red briefly
		const flash = this.add.rectangle(
			GAME_WIDTH / 2,
			GAME_HEIGHT / 2,
			GAME_WIDTH,
			GAME_HEIGHT,
			0xff0000,
			0.3
		)
		flash.setDepth(30)
		this.tweens.add({
			targets: flash,
			alpha: 0,
			duration: 400,
			onComplete: () => flash.destroy(),
		})

		// Show life lost text
		const message = this.lives > 0 ? '¡Se cayó!' : '¡Juego terminado!'
		const lostText = this.add.text(GAME_WIDTH / 2, GAME_HEIGHT / 2, message, {
			fontFamily: GAME_FONT,
			fontSize: '36px',
			color: '#ff4444',
			stroke: '#000000',
			strokeThickness: 6,
			align: 'center',
		})
		lostText.setOrigin(0.5)
		lostText.setDepth(25)
		lostText.setResolution(2)

		this.tweens.add({
			targets: lostText,
			scale: { from: 0.5, to: 1.3 },
			alpha: { from: 1, to: 0 },
			duration: 1200,
			ease: 'Power2',
			onComplete: () => {
				lostText.destroy()
				if (this.lives <= 0) {
					this.endGame()
				} else {
					this.resetBall()
				}
			},
		})
	}

	private resetBall() {
		const body = this.ball.body as Phaser.Physics.Arcade.Body
		if (!body) return

		body.setVelocity(0, 0)
		body.setAccelerationX(0)
		body.setGravityY(0)
		this.ball.setPosition(BALL.startX, BALL.startY)
		this.ball.setAngle(0)
		this.ball.setAlpha(1)
		this.ball.setScale(1)
		this.spinRate = 0

		// Reset portal state
		this.cornerKickHistory = []
		this.isPortalActive = false
		if (this.portalGraphics) {
			this.portalGraphics.destroy()
			this.portalGraphics = null
		}

		// Countdown before resuming play (isResetting stays true)
		this.startCountdown(() => {
			const b = this.ball.body as Phaser.Physics.Arcade.Body
			if (b) {
				b.setGravityY(this.currentGravity)
			}
			this.isResetting = false
		})
	}

	private endGame() {
		this.isGameOver = true

		soccerJugglingAudio.playGameOver()

		// Notify React
		const onGameOver = this.registry.get('onGameOver')
		if (onGameOver) onGameOver(this.score, this.kicks)
	}

	update(time: number, delta: number) {
		if (this.isGameOver || this.isPaused || this.isCountingDown) return
		if (this.isPortalActive) return

		const body = this.ball.body as Phaser.Physics.Arcade.Body
		if (!body) return

		// Check floor collision
		if (
			this.ball.y >= LAYOUT.floorY - PHYSICS.ballRadius &&
			!this.isResetting
		) {
			body.setVelocity(0, 0)
			this.ball.y = LAYOUT.floorY - PHYSICS.ballRadius
			this.handleLifeLost()
			return
		}

		// Wall bouncing
		if (this.ball.x <= PHYSICS.ballRadius) {
			this.ball.x = PHYSICS.ballRadius
			body.setVelocityX(
				Math.abs(body.velocity.x) * PHYSICS.wallBounceVelocityDampen
			)
			body.setVelocityY(body.velocity.y + this.spinRate * SPIN.wallSpinTransfer)
			this.spinRate *= -SPIN.wallSpinDampen
		} else if (this.ball.x >= GAME_WIDTH - PHYSICS.ballRadius) {
			this.ball.x = GAME_WIDTH - PHYSICS.ballRadius
			body.setVelocityX(
				-Math.abs(body.velocity.x) * PHYSICS.wallBounceVelocityDampen
			)
			body.setVelocityY(body.velocity.y - this.spinRate * SPIN.wallSpinTransfer)
			this.spinRate *= -SPIN.wallSpinDampen
		}

		// Ceiling bounce
		if (this.ball.y <= PHYSICS.ballRadius) {
			this.ball.y = PHYSICS.ballRadius
			body.setVelocityY(Math.abs(body.velocity.y) * 0.5)
			this.spinRate *= SPIN.ceilingSpinDampen
		}

		// Combo timeout check
		if (this.combo > 0 && time - this.lastKickTime > SCORING.comboTimeoutMs) {
			this.combo = 0
			this.updateHUD()
		}

		// Wind + Magnus combined acceleration
		let totalAccelX = 0

		if (this.kicks >= WIND.activateAfterKicks) {
			if (time - this.lastWindChange > WIND.changeIntervalMs) {
				this.lastWindChange = time
				this.windDirection = Math.random() > 0.5 ? 1 : -1
				const kicksOver = this.kicks - WIND.activateAfterKicks
				this.windForce = Math.min(
					WIND.maxStrength,
					WIND.initialStrength + kicksOver * WIND.strengthGrowthPerKick
				)
			}
			totalAccelX += this.windDirection * this.windForce
			this.updateWindIndicator()
		}

		// Magnus effect
		if (Math.abs(this.spinRate) > 1) {
			totalAccelX += this.spinRate * SPIN.magnusStrength
		}

		body.setAccelerationX(totalAccelX)

		// Spin decay (frame-rate independent)
		this.spinRate *= Math.pow(SPIN.spinDecayRate, delta / 16.67)
		if (Math.abs(this.spinRate) < 0.5) this.spinRate = 0

		// Visual rotation follows spin
		this.ball.angle += this.spinRate * (delta / 1000)

		// Update shadow
		const ballHeight = LAYOUT.floorY - this.ball.y
		const maxHeight = LAYOUT.floorY - 50
		const heightRatio = Phaser.Math.Clamp(ballHeight / maxHeight, 0.3, 1)

		this.ballShadow.setPosition(this.ball.x, LAYOUT.floorY - 4)
		this.ballShadow.setScale(1.2 - heightRatio * 0.5, 1)
		this.ballShadow.setAlpha(0.55 - heightRatio * 0.25)
	}
}
