import Phaser from 'phaser'
import { GAME_WIDTH, GAME_HEIGHT, LAYOUT } from '../constants'

export class BootScene extends Phaser.Scene {
	constructor() {
		super({ key: 'BootScene' })
	}

	preload() {
		// Show loading bar
		const progressBar = this.add.graphics()
		const progressBox = this.add.graphics()

		progressBox.fillStyle(0x222222, 0.8)
		progressBox.fillRect(GAME_WIDTH / 2 - 160, GAME_HEIGHT / 2 - 25, 320, 50)

		const loadingText = this.add.text(
			GAME_WIDTH / 2,
			GAME_HEIGHT / 2 - 50,
			'Cargando...',
			{ font: '20px Arial', color: '#ffffff' }
		)
		loadingText.setOrigin(0.5, 0.5)

		this.load.on('progress', (value: number) => {
			progressBar.clear()
			progressBar.fillStyle(0x22c55e, 1)
			progressBar.fillRect(
				GAME_WIDTH / 2 - 150,
				GAME_HEIGHT / 2 - 15,
				300 * value,
				30
			)
		})

		this.load.on('complete', () => {
			progressBar.destroy()
			progressBox.destroy()
			loadingText.destroy()
		})

		// Load assets (skin overrides or defaults)
		const skin = this.registry.get('skin') as string | undefined
		const basePath = '/games/soccer-juggling/'

		if (skin) {
			this.load.image('soccer-ball', `${basePath}skins/${skin}/ball.webp`)
			this.load.image('background', `${basePath}skins/${skin}/background.webp`)
		} else {
			this.load.image('soccer-ball', `${basePath}ball.webp`)
			this.load.image('background', `${basePath}background.webp`)
		}
	}

	async create() {
		// Generate background texture as fallback if image didn't load
		if (!this.textures.exists('background')) {
			this.generateBackgroundTexture()
		}

		// Generate particle textures procedurally
		this.generateKickParticleTexture()
		this.generateStarParticleTexture()
		this.generatePortalParticleTexture()

		// Wait for Luckiest Guy font to load before starting game
		try {
			const fontLoadPromise = document.fonts.load('bold 20px "Luckiest Guy"')
			const timeoutPromise = new Promise(resolve => setTimeout(resolve, 2000))
			await Promise.race([fontLoadPromise, timeoutPromise])
			await document.fonts.ready
		} catch {
			// Font might already be loaded or fail to load, continue anyway
		}

		this.scene.start('MainScene')
	}

	private generateKickParticleTexture() {
		const size = 16
		const g = this.add.graphics()
		const cx = size / 2
		const cy = size / 2

		// Soft glowing circle with alpha falloff
		for (let i = 3; i >= 0; i--) {
			const alpha = 0.3 - i * 0.06
			const r = (size / 2) * ((i + 1) / 4)
			g.fillStyle(0xffffff, alpha)
			g.fillCircle(cx, cy, r)
		}

		// Bright center
		g.fillStyle(0xffffff, 0.9)
		g.fillCircle(cx, cy, 2)

		g.generateTexture('kick-particle', size, size)
		g.destroy()
	}

	private generateBackgroundTexture() {
		const g = this.make.graphics({ x: 0, y: 0 })

		// Sky gradient
		const skySteps = 40
		for (let i = 0; i < skySteps; i++) {
			const t = i / skySteps
			const topR = (LAYOUT.skyGradientTop >> 16) & 0xff
			const topG = (LAYOUT.skyGradientTop >> 8) & 0xff
			const topB = LAYOUT.skyGradientTop & 0xff
			const botR = (LAYOUT.skyGradientBottom >> 16) & 0xff
			const botG = (LAYOUT.skyGradientBottom >> 8) & 0xff
			const botB = LAYOUT.skyGradientBottom & 0xff

			const r = Math.floor(topR + (botR - topR) * t)
			const gC = Math.floor(topG + (botG - topG) * t)
			const b = Math.floor(topB + (botB - topB) * t)
			const color = (r << 16) | (gC << 8) | b

			const yStart = (i / skySteps) * (LAYOUT.floorY - LAYOUT.grassHeight)
			const yEnd = ((i + 1) / skySteps) * (LAYOUT.floorY - LAYOUT.grassHeight)
			g.fillStyle(color, 1)
			g.fillRect(0, yStart, GAME_WIDTH, yEnd - yStart + 1)
		}

		// Stadium silhouette at horizon
		g.fillStyle(LAYOUT.stadiumSilhouetteColor, 0.3)
		const horizonY = LAYOUT.floorY - LAYOUT.grassHeight
		g.beginPath()
		g.moveTo(0, horizonY)
		g.lineTo(0, horizonY - 30)
		g.lineTo(30, horizonY - 40)
		g.lineTo(60, horizonY - 50)
		g.lineTo(100, horizonY - 55)
		g.lineTo(140, horizonY - 45)
		g.lineTo(160, horizonY - 55)
		g.lineTo(200, horizonY - 60)
		g.lineTo(240, horizonY - 55)
		g.lineTo(260, horizonY - 45)
		g.lineTo(300, horizonY - 55)
		g.lineTo(340, horizonY - 50)
		g.lineTo(370, horizonY - 40)
		g.lineTo(GAME_WIDTH, horizonY - 30)
		g.lineTo(GAME_WIDTH, horizonY)
		g.closePath()
		g.fillPath()

		// Grass field
		g.fillStyle(LAYOUT.grassColor, 1)
		g.fillRect(
			0,
			LAYOUT.floorY - LAYOUT.grassHeight,
			GAME_WIDTH,
			LAYOUT.grassHeight
		)

		// Grass stripes (mowing pattern)
		g.fillStyle(LAYOUT.grassDarkColor, 0.3)
		const stripeWidth = 30
		for (let x = 0; x < GAME_WIDTH; x += stripeWidth * 2) {
			g.fillRect(
				x,
				LAYOUT.floorY - LAYOUT.grassHeight,
				stripeWidth,
				LAYOUT.grassHeight
			)
		}

		// Danger zone (red gradient near floor)
		for (let i = 0; i < LAYOUT.dangerZoneHeight; i++) {
			const alpha = (i / LAYOUT.dangerZoneHeight) * 0.15
			g.fillStyle(LAYOUT.dangerZoneColor, alpha)
			g.fillRect(0, LAYOUT.floorY - LAYOUT.dangerZoneHeight + i, GAME_WIDTH, 1)
		}

		// Floor line
		g.lineStyle(3, 0xffffff, 0.6)
		g.lineBetween(0, LAYOUT.floorY, GAME_WIDTH, LAYOUT.floorY)

		// Below floor (dark)
		g.fillStyle(0x1a1a2e, 1)
		g.fillRect(0, LAYOUT.floorY, GAME_WIDTH, GAME_HEIGHT - LAYOUT.floorY)

		g.generateTexture('background', GAME_WIDTH, GAME_HEIGHT)
		g.destroy()
	}

	private generatePortalParticleTexture() {
		const size = 12
		const g = this.add.graphics()
		const cx = size / 2
		const cy = size / 2

		// Purple circle
		g.fillStyle(0x8844ff, 0.8)
		g.fillCircle(cx, cy, size / 2)

		// White center
		g.fillStyle(0xffffff, 0.9)
		g.fillCircle(cx, cy, 2)

		g.generateTexture('portal-particle', size, size)
		g.destroy()
	}

	private generateStarParticleTexture() {
		const size = 16
		const g = this.add.graphics()
		const cx = size / 2
		const cy = size / 2

		g.fillStyle(0xffd700, 1)
		g.beginPath()
		for (let i = 0; i < 10; i++) {
			const radius = i % 2 === 0 ? 7 : 3
			const angle = (i * Math.PI) / 5 - Math.PI / 2
			const x = cx + Math.cos(angle) * radius
			const y = cy + Math.sin(angle) * radius
			if (i === 0) {
				g.moveTo(x, y)
			} else {
				g.lineTo(x, y)
			}
		}
		g.closePath()
		g.fillPath()

		g.generateTexture('star-particle', size, size)
		g.destroy()
	}
}
